-- Função: get_top_artistas_ano
CREATE OR REPLACE FUNCTION public.get_top_artistas_ano(p_bar_id integer, p_ano integer, p_limit integer DEFAULT 15) RETURNS TABLE(artista text, shows bigint, mediapublico numeric, mediafaturamento numeric) LANGUAGE plpgsql SET search_path TO 'public', 'pg_temp'
AS $$ BEGIN RETURN QUERY SELECT ea.artista_nome::TEXT, COUNT(DISTINCT e.id)::BIGINT, ROUND(AVG(e.publico_real))::NUMERIC, ROUND(AVG(e.faturamento_liquido), 2)::NUMERIC FROM eventos e INNER JOIN evento_artista ea ON ea.evento_id = e.id WHERE e.bar_id = p_bar_id AND EXTRACT(YEAR FROM e.data_evento) = p_ano AND ea.artista_nome IS NOT NULL AND ea.artista_nome != '' GROUP BY ea.artista_nome HAVING COUNT(DISTINCT e.id) >= 2 ORDER BY AVG(e.faturamento_liquido) DESC LIMIT p_limit; END; $$;
